parameters.jsCode:
// ================================================
// NEW HIRE PAYLOAD PARSER and VALIDATOR
// ================================================

const body = $input.first().json;
const rawHires = Array.isArray(body) ? body : [body];

const processedItems = [];

for (const hire of rawHires) {
  const props = hire.employee || hire;

  const firstName = (props.first_name || props.firstName || '').trim();
  const lastName = (props.last_name || props.lastName || '').trim();
  const personalEmail = (props.personal_email || props.email || '').toLowerCase().trim();

  // Skip records missing required identity fields
  if (!firstName || !lastName) {
    console.log('Skipping: missing first or last name');
    continue;
  }

  processedItems.push({
    json: {
      firstName,
      lastName,
      fullName: [firstName, lastName].filter(Boolean).join(' '),
      personalEmail,
      department: props.department || props.dept || 'General',
      jobTitle: props.job_title || props.title || 'New Employee',
      managerName: props.manager_name || props.manager || 'Unknown',
      managerEmail: (props.manager_email || '').toLowerCase().trim(),
      startDate: props.start_date || props.startDate || '',
      location: props.location || props.office || 'Remote',
      employeeId: props.employee_id || props.id || '',
      processedAt: new Date().toISOString(),
      _parseError: false
    }
  });
}

if (processedItems.length === 0) {
  return [{
    json: {
      fullName: '',
      firstName: '',
      lastName: '',
      _parseError: true
    }
  }];
}

return processedItems;

